const ParallaxSection = ({ children, speed = 0.1, className = "" }: { children: React.ReactNode, speed?: number, className?: string }) => {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start end", "end start"]
  });

  const y = useTransform(scrollYProgress, [0, 1], ["0%", `${speed * 100}%`]);
  const opacity = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [0, 1, 1, 0]);

  return (
    <motion.div ref={ref} style={{ y, opacity }} className={className}>
      {children}
    </motion.div>
  );
};

const MouseParallax = ({ children, factor = 20, className = "" }: { children: React.ReactNode, factor?: number, className?: string }) => {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const springX = useSpring(x, { damping: 30, stiffness: 100 });
  const springY = useSpring(y, { damping: 30, stiffness: 100 });

  const handleMouseMove = (e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    x.set((e.clientX - centerX) / factor);
    y.set((e.clientY - centerY) / factor);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <motion.div
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{ x: springX, y: springY }}
      className={className}
    >
      {children}
    </motion.div>
  );
};

const FadeInWhenVisible = ({ children, delay = 0 }: { children: React.ReactNode, delay?: number }) => {
  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-150px" }}
      transition={{
        duration: 0.6,
        ease: "easeOut",
        delay: delay
      }}
      className="h-full"
    >
      {children}
    </motion.div>
  );
};

const CinematicBackground = () => {
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isHovering, setIsHovering] = useState(false);
  const { isHoveringCard } = React.useContext(MouseGlowContext);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();

      // Check if mouse is within vertical bounds of this section
      const isInside = e.clientY >= rect.top && e.clientY <= rect.bottom;
      setIsHovering(isInside);

      if (isInside) {
        mouseX.set(e.clientX - rect.left);
        mouseY.set(e.clientY - rect.top);
      }
    };

    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, [mouseX, mouseY]);

  return (
    <div ref={containerRef} className="absolute inset-0 pointer-events-none overflow-hidden">
      {/* Static Dark Base */}
      <div className="absolute inset-0 bg-[#0F0B14]" />

      {/* Subtle Gradient Depth */}
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-[#1A1322]/20 to-transparent" />

      {/* Soft Cinematic Lighting - Very Minimal */}
      <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_20%_20%,rgba(116,44,134,0.04)_0%,transparent_60%)]" />
      <div className="absolute bottom-0 right-0 w-full h-full bg-[radial-gradient(circle_at_80%_80%,rgba(116,44,134,0.03)_0%,transparent_60%)]" />

      {/* Interactive Spotlight Glow */}
      <motion.div
        className="absolute h-[800px] w-[800px] rounded-full bg-[radial-gradient(circle_at_center,rgba(116,44,134,0.18)_0%,transparent_70%)] blur-[80px]"
        style={{
          x: useTransform(mouseX, (x) => x - 400),
          y: useTransform(mouseY, (y) => y - 400),
          opacity: isHovering ? (isHoveringCard ? 0 : 1) : 0
        }}
        animate={{ opacity: isHovering ? (isHoveringCard ? 0 : 1) : 0 }}
        transition={{ duration: 0.5 }}
      />

      {/* Floating Cinematic Dust Particles */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        {Array.from({ length: 15 }).map((_, i) => (
          <motion.div
            key={i}
            initial={{
              x: Math.random() * 100 + "%",
              y: Math.random() * 100 + "%",
              opacity: 0,
              scale: Math.random() * 0.5 + 0.5
            }}
            animate={{
              y: [null, "-20%"],
              opacity: [0, 0.15, 0],
              x: [null, (Math.random() - 0.5) * 5 + "%"]
            }}
            transition={{
              duration: Math.random() * 20 + 20,
              repeat: Infinity,
              ease: "linear",
              delay: Math.random() * 10
            }}
            className="absolute w-1 h-1 bg-white/20 rounded-full blur-[1px]"
          />
        ))}
      </div>
    </div>
  );
};

const Navbar = ({ activeSection, onNavItemClick }: { activeSection: string, onNavItemClick: (id: string) => void }) => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    console.log("Active Section ID:", activeSection);
  }, [activeSection]);

  const navLinks = [
    { name: 'Home', href: '#home', id: 'home' },
    { name: 'Studio', href: '#studio', id: 'studio' },
    { name: 'Services', href: '#services', id: 'services' },
    { name: 'Games', href: '#projects', id: 'projects' },
    { name: 'Careers', href: '#careers', id: 'careers' },
    { name: 'Contact', href: '#contact', id: 'contact' },
  ];

  return (
    <nav className={`fixed top-0 left-0 w-full z-50 transition-all duration-500 ${scrolled ? 'bg-bg-dark/90 backdrop-blur-md py-4 border-b border-divider' : 'bg-transparent py-8'}`}>
      <div className="container-1440 flex justify-between items-center">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="flex items-center"
        >
          <HeaderLogo className="h-10 w-auto text-text-light" />
        </motion.div>

        {/* Desktop Nav */}
        <div className="hidden md:flex gap-10 items-center">
          {navLinks.map((link, i) => (
            <motion.a
              key={link.name}
              href={link.href}
              onClick={(e) => {
                e.preventDefault();
                onNavItemClick(link.id);
              }}
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1 }}
              className={`text-sm font-medium tracking-widest transition-all duration-300 uppercase relative group ${activeSection === link.id ? 'text-primary' : 'text-text-light/90 hover:text-primary'
                }`}
            >
              {link.name}
              <span className={`absolute -bottom-2 left-0 h-[2px] bg-primary transition-all duration-300 ${activeSection === link.id ? 'w-full' : 'w-0 group-hover:w-full'
                }`} />
            </motion.a>
          ))}
        </div>

        {/* Mobile Toggle */}
        <button className="md:hidden text-text-light" onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
          {mobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu */}
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="md:hidden bg-bg-section border-b border-divider overflow-hidden"
          >
            <div className="flex flex-col p-6 gap-4">
              {navLinks.map((link) => (
                <a
                  key={link.name}
                  href={link.href}
                  className={`text-lg font-medium transition-colors ${activeSection === link.id ? 'text-primary' : 'text-text-muted hover:text-primary'
                    }`}
                  onClick={(e) => {
                    e.preventDefault();
                    setMobileMenuOpen(false);
                    onNavItemClick(link.id);
                  }}
                >
                  {link.name}
                </a>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

